*** Begin Patch
*** Add File: C:\Users\KSR\Documents\Codex\2026-06-03\new-chat-2\work\cleanup-ksr-only.ps1
+$ErrorActionPreference = 'Continue'
+$LogPath = 'C:\Users\KSR\Documents\Codex\2026-06-03\new-chat-2\outputs\ksr-profile-cleanup.log'
+New-Item -ItemType Directory -Path (Split-Path $LogPath -Parent) -Force | Out-Null
+
+function Write-Log {
+  param([string]$Message)
+  $line = "$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss') $Message"
+  Add-Content -LiteralPath $LogPath -Value $line -Encoding UTF8
+  Write-Output $line
+}
+
+Write-Log 'Starting KSR-only profile cleanup.'
+
+$usersToRemove = @('사론김', 'SpotlightTest', 'CodexSandboxOnline', 'CodexSandboxOffline')
+$profilePathsToRemove = @(
+  'C:\Users\final',
+  'C:\Users\SpotlightTest',
+  'C:\Users\CodexSandboxOnline',
+  'C:\Users\CodexSandboxOffline'
+)
+
+try {
+  $sessions = (query user) 2>$null
+  foreach ($line in $sessions) {
+    if ($line -match '^\s*(spotlighttest|사론김)\s+\S*\s+(\d+)\s+') {
+      $id = [int]$Matches[2]
+      Write-Log "Logging off stale session $id for $($Matches[1])."
+      logoff $id 2>&1 | ForEach-Object { Write-Log $_ }
+    }
+  }
+} catch {
+  Write-Log "Session query/logoff failed: $($_.Exception.Message)"
+}
+
+Start-Sleep -Seconds 2
+
+foreach ($name in $usersToRemove) {
+  $user = Get-LocalUser -Name $name -ErrorAction SilentlyContinue
+  if ($user) {
+    Write-Log "Removing local user: $name"
+    Remove-LocalUser -Name $name -ErrorAction Continue
+  } else {
+    Write-Log "Local user already absent: $name"
+  }
+}
+
+foreach ($path in $profilePathsToRemove) {
+  $resolved = $null
+  try { $resolved = (Resolve-Path -LiteralPath $path -ErrorAction SilentlyContinue).Path } catch {}
+  if (-not $resolved) {
+    Write-Log "Profile folder already absent: $path"
+    continue
+  }
+  if (-not ($resolved -like 'C:\Users\*')) {
+    Write-Log "Skipped unexpected path outside C:\Users: $resolved"
+    continue
+  }
+  if ($resolved -ieq 'C:\Users\KSR' -or $resolved -ieq 'C:\Users\Public' -or $resolved -ieq 'C:\Users\Default') {
+    Write-Log "Skipped protected profile path: $resolved"
+    continue
+  }
+
+  $profile = Get-CimInstance Win32_UserProfile | Where-Object { $_.LocalPath -ieq $resolved } | Select-Object -First 1
+  if ($profile) {
+    Write-Log "Deleting registered profile: $resolved"
+    try {
+      $result = Invoke-CimMethod -InputObject $profile -MethodName Delete -ErrorAction Stop
+      Write-Log "Win32_UserProfile.Delete result for $resolved: ReturnValue=$($result.ReturnValue)"
+    } catch {
+      Write-Log "Registered profile delete failed for $resolved: $($_.Exception.Message)"
+    }
+  }
+
+  if (Test-Path -LiteralPath $resolved) {
+    Write-Log "Removing leftover folder: $resolved"
+    Remove-Item -LiteralPath $resolved -Recurse -Force -ErrorAction Continue
+  }
+}
+
+Write-Log 'Remaining local users:'
+Get-LocalUser | Select-Object Name,Enabled,SID | ForEach-Object {
+  Write-Log "  $($_.Name) Enabled=$($_.Enabled) SID=$($_.SID)"
+}
+
+Write-Log 'Remaining C:\Users entries:'
+Get-ChildItem C:\Users -Force | Select-Object Name,Mode | ForEach-Object {
+  Write-Log "  $($_.Name) $($_.Mode)"
+}
+
+Write-Log 'Cleanup finished.'
*** End Patch

