*** Begin Patch
*** Add File: C:\Users\KSR\Documents\Codex\2026-06-03\new-chat-2\work\cleanup-ksr-only.ps1
+$ErrorActionPreference = 'Continue'
+$LogPath = 'C:\Users\KSR\Documents\Codex\2026-06-03\new-chat-2\outputs\ksr-profile-cleanup.log'
+New-Item -ItemType Directory -Path (Split-Path $LogPath -Parent) -Force | Out-Null
+
+function Write-Log {
+  param([string]$Message)
+  $line = "$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss') $Message"
+  Add-Content -LiteralPath $LogPath -Value $line -Encoding UTF8
+  Write-Output $line
+}
+
+Write-Log 'Starting SID-based KSR-only cleanup.'
+
+$keepSidSuffix = '-1006'
+$removeSidSuffixes = @('-1001', '-1003', '-1004', '-1005')
+$removeProfilePaths = @(
+  'C:\Users\final',
+  'C:\Users\SpotlightTest',
+  'C:\Users\CodexSandboxOnline',
+  'C:\Users\CodexSandboxOffline'
+)
+
+try {
+  $currentLine = (query user) 2>$null | Where-Object { $_ -match '^>' } | Select-Object -First 1
+  $currentSessionId = $null
+  if ($currentLine -match '^\>\s*\S+\s+\S+\s+(\d+)\s+') {
+    $currentSessionId = [int]$Matches[1]
+  }
+
+  $sessionLines = (query user) 2>$null
+  foreach ($line in $sessionLines) {
+    if ($line -match '^\s*>?\s*\S+\s+\S*\s+(\d+)\s+(Disc|Disconnected)\s+') {
+      $sessionId = [int]$Matches[1]
+      if ($currentSessionId -eq $null -or $sessionId -ne $currentSessionId) {
+        Write-Log "Logging off disconnected session id $sessionId."
+        logoff $sessionId 2>&1 | ForEach-Object { Write-Log $_ }
+      }
+    }
+  }
+} catch {
+  Write-Log "Session cleanup failed: $($_.Exception.Message)"
+}
+
+Start-Sleep -Seconds 5
+
+foreach ($user in (Get-LocalUser)) {
+  $sid = $user.SID.Value
+  if ($sid.EndsWith($keepSidSuffix)) {
+    Write-Log "Keeping user $($user.Name) SID=$sid."
+    continue
+  }
+  if ($removeSidSuffixes | Where-Object { $sid.EndsWith($_) }) {
+    Write-Log "Removing local user $($user.Name) SID=$sid."
+    Remove-LocalUser -SID $user.SID -ErrorAction Continue
+  }
