*** Begin Patch
*** Add File: C:\Users\KSR\Documents\Codex\2026-06-03\new-chat-2\work\repair-windows-spotlight-admin.ps1
+$ErrorActionPreference = 'Continue'
+$log = 'C:\Users\KSR\Documents\Codex\2026-06-03\new-chat-2\outputs\windows-spotlight-repair.log'
+New-Item -ItemType Directory -Path (Split-Path $log -Parent) -Force | Out-Null
+
+function Write-Log {
+  param([string]$Message)
+  $line = "$(Get-Date -Format 'yyyy-MM-dd HH:mm:ss') $Message"
+  Add-Content -LiteralPath $log -Value $line -Encoding UTF8
+  Write-Output $line
+}
+
+Write-Log 'Starting Windows Spotlight repair.'
+Write-Log 'Running DISM /Online /Cleanup-Image /RestoreHealth.'
+& dism.exe /Online /Cleanup-Image /RestoreHealth 2>&1 | ForEach-Object { Write-Log $_ }
+
+Write-Log 'Running sfc /scannow.'
+& sfc.exe /scannow 2>&1 | ForEach-Object { Write-Log $_ }
+
+Write-Log 'Re-registering ContentDeliveryManager and LockApp.'
+$cdmManifest = 'C:\Windows\SystemApps\Microsoft.Windows.ContentDeliveryManager_cw5n1h2txyewy\AppxManifest.xml'
+$lockManifest = 'C:\Windows\SystemApps\Microsoft.LockApp_cw5n1h2txyewy\AppxManifest.xml'
+if (Test-Path $cdmManifest) {
+  Add-AppxPackage -DisableDevelopmentMode -Register $cdmManifest 2>&1 | ForEach-Object { Write-Log $_ }
+}
+if (Test-Path $lockManifest) {
+  Add-AppxPackage -DisableDevelopmentMode -Register $lockManifest 2>&1 | ForEach-Object { Write-Log $_ }
+}
+
+Write-Log 'Ensuring required services are running.'
