*** Begin Patch
*** Add File: work/audit-profile-migration.ps1
+$ErrorActionPreference = 'Continue'
+[Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
+$OutputEncoding = [System.Text.UTF8Encoding]::new($false)
+
+$root = Split-Path -Parent $PSScriptRoot
+$outDir = Join-Path $root 'outputs'
+New-Item -ItemType Directory -Force -Path $outDir | Out-Null
+$stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
+$report = Join-Path $outDir "profile-migration-audit-$stamp.txt"
+$json = Join-Path $outDir "profile-migration-audit-$stamp.json"
+
+function Add-Line {
+    param([string]$Text = '')
+    $Text | Tee-Object -FilePath $report -Append
+}
+
+function Find-RegistryText {
+    param(
+        [string]$Root,
+        [string[]]$Needles
+    )
+    $hits = New-Object System.Collections.Generic.List[object]
+    $keys = Get-ChildItem -Path $Root -Recurse -ErrorAction SilentlyContinue
+    foreach ($key in @((Get-Item $Root -ErrorAction SilentlyContinue)) + $keys) {
+        if (-not $key) { continue }
+        foreach ($needle in $Needles) {
+            if ($key.Name -like "*$needle*") {
+                $hits.Add([pscustomobject]@{
+                    Hive = $Root
+                    Kind = 'KeyName'
+                    Key = $key.Name
+                    ValueName = ''
+                    Value = ''
+                    Needle = $needle
+                })
+            }
+        }
+        try {
+            $props = Get-ItemProperty -LiteralPath $key.PSPath -ErrorAction Stop
+            foreach ($prop in $props.PSObject.Properties) {
+                if ($prop.Name -like 'PS*') { continue }
+                $val = $prop.Value
+                $text = if ($null -eq $val) { '' } elseif ($val -is [array]) { ($val -join ';') } else { [string]$val }
+                foreach ($needle in $Needles) {
+                    if ($text -like "*$needle*" -or $prop.Name -like "*$needle*") {
+                        $hits.Add([pscustomobject]@{
+                            Hive = $Root
+                            Kind = 'Value'
+                            Key = $key.Name
+                            ValueName = $prop.Name
+                            Value = $text
+                            Needle = $needle
+                        })
+                    }
+                }
+            }
+        } catch {}
+    }
+    return $hits
+}
+
+$needles = @('C:\Users\final', 'C:/Users/final', '\Users\final', '/Users/final', 'final\Documents\Codex')
+
+Add-Line "Profile migration audit"
+Add-Line "Time: $(Get-Date -Format 'yyyy-MM-dd HH:mm:ss')"
+Add-Line "User: $env:USERNAME"
+Add-Line "UserProfile: $env:USERPROFILE"
+Add-Line ''
+
+$userShell = Get-ItemProperty 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\User Shell Folders' -ErrorAction SilentlyContinue
+$shell = Get-ItemProperty 'HKCU:\Software\Microsoft\Windows\CurrentVersion\Explorer\Shell Folders' -ErrorAction SilentlyContinue
+$envUser = Get-ItemProperty 'HKCU:\Environment' -ErrorAction SilentlyContinue
+$appPaths = @(
+    "$env:APPDATA",
+    "$env:LOCALAPPDATA",
+    "$env:USERPROFILE\Documents",
+    "$env:USERPROFILE\Desktop",
+    "$env:USERPROFILE\Downloads",
+    "$env:USERPROFILE\Pictures",
+    "$env:USERPROFILE\Videos",
+    "$env:USERPROFILE\Music"
+)
+
+$summary = [ordered]@{
+    UserShellFolders = $userShell
+    ShellFolders = $shell
+    UserEnvironment = $envUser
+    KnownFolderPaths = @()
+    HKCUFinalHits = @()
+    ProfileList = @()
+    LocalUsers = @()
+    ScheduledTaskFinalHits = @()
+    StartupFinalHits = @()
+    AppDataFinalPathFiles = @()
+}
+
+foreach ($p in $appPaths) {
+    $summary.KnownFolderPaths += [pscustomobject]@{ Path=$p; Exists=(Test-Path -LiteralPath $p) }
+}
+
