*** Begin Patch
*** Add File: work/run-admin-system-repair.ps1
+$ErrorActionPreference = 'Continue'
+[Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)
+$OutputEncoding = [System.Text.UTF8Encoding]::new($false)
+
+$root = Split-Path -Parent $PSScriptRoot
+$outDir = Join-Path $root 'outputs'
+New-Item -ItemType Directory -Force -Path $outDir | Out-Null
+$log = Join-Path $outDir 'admin-system-repair.log'
+$status = Join-Path $outDir 'admin-system-repair.status.json'
+
+function Write-Log {
+    param([string]$Message)
+    $line = "[{0}] {1}" -f (Get-Date -Format 'yyyy-MM-dd HH:mm:ss'), $Message
+    $line | Tee-Object -FilePath $log -Append
+}
+
+function Write-Status {
+    param([string]$Stage, [string]$State, [int]$Percent, [string]$Detail = '')
+    [pscustomobject]@{
+        Time = Get-Date -Format 'yyyy-MM-dd HH:mm:ss'
+        Stage = $Stage
+        State = $State
+        Percent = $Percent
+        Detail = $Detail
+    } | ConvertTo-Json | Set-Content -LiteralPath $status -Encoding UTF8
+}
+
+function Is-Admin {
+    $principal = New-Object Security.Principal.WindowsPrincipal([Security.Principal.WindowsIdentity]::GetCurrent())
+    return $principal.IsInRole([Security.Principal.WindowsBuiltInRole]::Administrator)
+}
+
+function Run-Step {
+    param([string]$Stage, [int]$Percent, [scriptblock]$Command)
+    Write-Status -Stage $Stage -State 'Running' -Percent $Percent
+    Write-Log "START: $Stage"
+    try {
+        & $Command 2>&1 | Tee-Object -FilePath $log -Append
+        $code = if ($null -ne $LASTEXITCODE) { $LASTEXITCODE } else { 0 }
+        Write-Log "END: $Stage exit=$code"
+        Write-Status -Stage $Stage -State 'Completed' -Percent $Percent -Detail "exit=$code"
+    } catch {
+        Write-Log "ERROR: $Stage $($_.Exception.Message)"
+        Write-Status -Stage $Stage -State 'Error' -Percent $Percent -Detail $_.Exception.Message
+    }
+}
+
+Write-Log 'Admin system repair started'
+if (-not (Is-Admin)) {
+    Write-Log 'Not running as administrator. Exiting.'
+    Write-Status -Stage 'Elevation' -State 'Error' -Percent 0 -Detail 'Administrator rights required'
+    exit 740
+}
+Write-Status -Stage 'Started' -State 'Running' -Percent 1 -Detail 'Administrator confirmed'
+
+Run-Step -Stage 'Defender Preferences and Suspicious Exclusions' -Percent 8 -Command {
+    $pref = Get-MpPreference
+    $pref | Select-Object DisableRealtimeMonitoring, DisableBehaviorMonitoring, DisableIOAVProtection, PUAProtection, MAPSReporting, SubmitSamplesConsent | Format-List
+    "Current Defender exclusions:"
+    $pref.ExclusionPath | ForEach-Object { "Path: $_" }
+    $pref.ExclusionProcess | ForEach-Object { "Process: $_" }
+    $pref.ExclusionExtension | ForEach-Object { "Extension: $_" }
+
+    Set-MpPreference -DisableRealtimeMonitoring $false -DisableBehaviorMonitoring $false -DisableIOAVProtection $false -PUAProtection Enabled -MAPSReporting Advanced -SubmitSamplesConsent SendSafeSamples
+
+    $badPatterns = @('C:\Users\final', 'KMS', 'KMSTools', 'Ratiborus', 'Office Installer', 'Add_Defender_Exclusion', 'setup_x64')
+    foreach ($path in @($pref.ExclusionPath)) {
+        if ($badPatterns | Where-Object { $path -like "*$_*" }) {
+            "Removing suspicious Defender path exclusion: $path"
+            Remove-MpPreference -ExclusionPath $path -ErrorAction SilentlyContinue
+        }
+    }
+    foreach ($proc in @($pref.ExclusionProcess)) {
+        if ($badPatterns | Where-Object { $proc -like "*$_*" }) {
+            "Removing suspicious Defender process exclusion: $proc"
+            Remove-MpPreference -ExclusionProcess $proc -ErrorAction SilentlyContinue
+        }
+    }
+}
+
+Run-Step -Stage 'DISM CheckHealth' -Percent 15 -Command {
+    dism.exe /Online /Cleanup-Image /CheckHealth
+}
+
+Run-Step -Stage 'DISM ScanHealth' -Percent 30 -Command {
+    dism.exe /Online /Cleanup-Image /ScanHealth
+}
+
+Run-Step -Stage 'DISM RestoreHealth' -Percent 45 -Command {
+    dism.exe /Online /Cleanup-Image /RestoreHealth
+}
+
+Run-Step -Stage 'SFC ScanNow' -Percent 60 -Command {
+    sfc.exe /scannow
+}
+
+Run-Step -Stage 'CHKDSK Online Scan C' -Percent 68 -Command {
+    chkdsk.exe C: /scan
+}
+
+Run-Step -Stage 'Gaming Services Check and Repair' -Percent 75 -Command {
+    Get-Service GamingServices* -ErrorAction SilentlyContinue | Select-Object Name, Status, StartType | Format-Table -AutoSize
+    foreach ($svc in Get-Service GamingServices* -ErrorAction SilentlyContinue) {
+        try {
+            Set-Service -Name $svc.Name -StartupType Manual -ErrorAction SilentlyContinue
+            Start-Service -Name $svc.Name -ErrorAction SilentlyContinue
+        } catch {
+            "Service start failed: $($svc.Name) $($_.Exception.Message)"
+        }
+    }
+    $pkg = Get-AppxPackage -AllUsers Microsoft.GamingServices -ErrorAction SilentlyContinue | Select-Object -First 1
+    if ($pkg -and (Test-Path (Join-Path $pkg.InstallLocation 'AppxManifest.xml'))) {
+        "Re-registering GamingServices package: $($pkg.PackageFullName)"
+        Add-AppxPackage -DisableDevelopmentMode -Register (Join-Path $pkg.InstallLocation 'AppxManifest.xml') -ErrorAction Continue
+    } else {
+        'GamingServices package not found.'
+    }
+    Get-Service GamingServices* -ErrorAction SilentlyContinue | Select-Object Name, Status, StartType | Format-Table -AutoSize
+}
+
+Run-Step -Stage 'Realtek Bluetooth Restart' -Percent 82 -Command {
+    $id = 'USB\VID_0BDA&PID_8771\00E04C239987'
+    pnputil.exe /restart-device $id
+    Start-Sleep -Seconds 5
+    Get-PnpDevice -InstanceId $id -ErrorAction SilentlyContinue | Select-Object Status, FriendlyName, InstanceId, Problem, ConfigManagerErrorCode | Format-List
+}
+
+Run-Step -Stage 'Lock Screen Windows Spotlight Values' -Percent 88 -Command {
+    $sid = (Get-CimInstance Win32_UserAccount -Filter "Name='KSR'").SID
+    $hkuPath = "Registry::HKEY_USERS\$sid\Software\Microsoft\Windows\CurrentVersion"
+    $lockReg = Join-Path $hkuPath 'Lock Screen'
+    $cdmReg = Join-Path $hkuPath 'ContentDeliveryManager'
+    New-Item -Path $lockReg -Force | Out-Null
+    New-Item -Path $cdmReg -Force | Out-Null
+    New-ItemProperty -Path $lockReg -Name 'LockAppAumId' -Value 'Microsoft.LockApp_cw5n1h2txyewy!WindowsDefaultLockScreen' -PropertyType String -Force | Out-Null
+    New-ItemProperty -Path $lockReg -Name 'SlideshowEnabled' -Value 0 -PropertyType DWord -Force | Out-Null
+    New-ItemProperty -Path $lockReg -Name 'LockInstanceType' -Value 3 -PropertyType DWord -Force | Out-Null
+    $values = @{
+        ContentDeliveryAllowed = 1
+        FeatureManagementEnabled = 1
+        RotatingLockScreenEnabled = 1
+        RotatingLockScreenOverlayEnabled = 1
+        'SubscribedContent-338387Enabled' = 1
+        'SubscribedContent-338388Enabled' = 1
+        'SubscribedContent-338389Enabled' = 1
+        'SubscribedContent-353694Enabled' = 1
+        'SubscribedContent-353696Enabled' = 1
+        SystemPaneSuggestionsEnabled = 1
+        SoftLandingEnabled = 1
+    }
+    foreach ($entry in $values.GetEnumerator()) {
+        New-ItemProperty -Path $cdmReg -Name $entry.Key -Value $entry.Value -PropertyType DWord -Force | Out-Null
+    }
+    Get-ItemProperty $lockReg | Select-Object LockAppAumId, SlideshowEnabled, LockInstanceType | Format-List
+    Get-ItemProperty $cdmReg | Select-Object ContentDeliveryAllowed, RotatingLockScreenEnabled, RotatingLockScreenOverlayEnabled | Format-List
+}
+
+Run-Step -Stage 'Defender Signature Update' -Percent 90 -Command {
+    Update-MpSignature
+}
+
+Run-Step -Stage 'Defender FullScan' -Percent 95 -Command {
+    Start-MpScan -ScanType FullScan
+    Get-MpThreatDetection -ErrorAction SilentlyContinue | Format-List
+}
+
+Write-Status -Stage 'Complete' -State 'Completed' -Percent 100
+Write-Log 'Admin system repair completed'
*** End Patch

